import{_ as t,a,b as s}from"./chunks/支持留言.NiGCLVdp.js";import{_ as i,o,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"th-TH/Other/blog.md","filePath":"th-TH/Other/blog.md","lastUpdated":1781962217000}'),n={name:"th-TH/Other/blog.md"};function r(c,e,d,g,h,u){return o(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog feature เพิ่ม blog page แบบ standalone ให้ ImgBed site ของคุณ</p><p>หลัง enable แล้ว visitors เปิดได้ที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+t+'" alt="Blog homepage" loading="lazy"></p><p>Blog ดัดแปลงมาจาก open-source project <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> โดย ImgBed rewrite และ integrate กับ Vue เพื่อให้ทำงานเป็นส่วนหนึ่งของ image hosting site</p><h2 id="ตั้งค่าที่ไหน" tabindex="-1">ตั้งค่าที่ไหน <a class="header-anchor" href="#ตั้งค่าที่ไหน" aria-label="Permalink to &quot;ตั้งค่าที่ไหน&quot;">​</a></h2><p>Blog settings อยู่ที่:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Blog settings" loading="lazy"></p><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li>เปิด <code>Enable</code></li><li>เลือก GitHub account ที่ใช้เก็บ blog configuration</li><li>คลิก <code>Update Blog</code></li><li>รอ success message</li><li>เปิด <code>https://your-domain.com/blog/</code> เพื่อดู blog</li></ol><p>ครั้งแรกที่ใช้ ImgBed จะเตรียม private GitHub repository ภายใต้ account ที่เลือก:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Repository นี้เก็บ blog settings และ article content</p><h2 id="เขียน-posts" tabindex="-1">เขียน Posts <a class="header-anchor" href="#เขียน-posts" aria-label="Permalink to &quot;เขียน Posts&quot;">​</a></h2><p>Edit blog posts ใน private GitHub repository:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typical workflow:</p><ol><li>เปิด GitHub</li><li>เข้า private repository <code>imgbed-blog-config</code></li><li>Edit หรือ add post files</li><li>Commit changes</li><li>กลับไปที่ ImgBed admin panel แล้วคลิก <code>Update Blog</code> หรือคลิก logo มุมซ้ายบนของ blog homepage สามครั้งเพื่อ trigger blog update</li></ol><p><code>Update Blog</code> จะไม่ overwrite content ที่คุณเขียนไว้ แต่ใช้ initialize repository เมื่อจำเป็นและ refresh blog cache</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>Blog รองรับ features ทั่วไป เช่น post lists, categories, tags, archives, search, dark mode และ language switching</p><p>รองรับ comments และ visit statistics ด้วย</p><p><img src="'+s+'" alt="Blog comments" loading="lazy"></p><p>Comments จะแสดงใต้ posts Visitors สามารถ submit avatar, nickname, email และ comment content ได้</p><p>Visit statistics แสดง post views และ site visits ช่วยให้เข้าใจ blog traffic</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog จะ serve ใต้ <code>/blog/</code> เสมอ</p><p>เช่น ถ้า ImgBed domain คือ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>Blog URL คือ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>หลัง disable blog แล้ว visitors จะเข้าถึง blog page ไม่ได้</p>',34)])])}const f=i(n,[["render",r]]);export{v as __pageData,f as default};
